function MusicPlayer() {
  const [tracks, setTracks] = React.useState([
    {title:'REPLACE_WITH_SONG_1',artist:'REPLACE_WITH_ARTIST_1',url:'REPLACE_WITH_URL_1'},
    {title:'Song 2',artist:'Artist 2',url:''},
    {title:'Song 3',artist:'Artist 3',url:''}
  ]);
  const [current, setCurrent] = React.useState(0);
  const [playing, setPlaying] = React.useState(false);
  const [progress, setProgress] = React.useState(0);
  const audioRef = React.useRef(null);

  React.useEffect(()=>{
    const audio = audioRef.current;
    if(!audio)return;
    const update = ()=>setProgress(audio.currentTime/audio.duration*100||0);
    audio.addEventListener('timeupdate',update);
    return ()=>audio.removeEventListener('timeupdate',update);
  },[]);

  const toggle = ()=>{
    const audio = audioRef.current;
    if(!audio)return;
    if(playing){audio.pause();}else{audio.play().catch(()=>{});}
    setPlaying(!playing);
  };

  const next = ()=>setCurrent((current+1)%tracks.length);
  const prev = ()=>setCurrent((current-1+tracks.length)%tracks.length);

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Music Player</div>
      <div style={{textAlign:'center',marginBottom:12}}>
        <div style={{width:80,height:80,borderRadius:'50%',background:'linear-gradient(135deg,#667eea,#764ba2)',margin:'0 auto 10px',display:'flex',alignItems:'center',justifyContent:'center',fontSize:28}}>
          🎵
        </div>
        <div style={{fontSize:16,fontWeight:600}}>{tracks[current].title}</div>
        <div style={{fontSize:13,color:'#888'}}>{tracks[current].artist}</div>
      </div>
      <div style={{height:4,background:'#eee',borderRadius:2,marginBottom:12}}>
        <div style={{width:`${progress}%`,height:'100%',background:'#667eea',borderRadius:2}}/>
      </div>
      <div style={{display:'flex',justifyContent:'center',gap:16,marginBottom:12}}>
        <button onClick={prev} style={{background:'none',border:'none',fontSize:20,cursor:'pointer'}}>⏮</button>
        <button onClick={toggle} style={{width:44,height:44,borderRadius:'50%',border:'none',background:'#667eea',color:'#fff',fontSize:18,cursor:'pointer'}}>
          {playing?'⏸':'▶'}
        </button>
        <button onClick={next} style={{background:'none',border:'none',fontSize:20,cursor:'pointer'}}>⏭</button>
      </div>
      <div style={{flex:1,overflow:'auto'}}>
        {tracks.map((t,i)=> (
          <div key={i} onClick={()=>setCurrent(i)}
            style={{padding:'8px 10px',borderRadius:6,cursor:'pointer',background:i===current?'#f0f0ff':'transparent',display:'flex',justifyContent:'space-between'}}>
            <span style={{fontSize:13}}>{t.title} — {t.artist}</span>
            {i===current && <span style={{fontSize:12,color:'#667eea'}}>▶</span>}
          </div>
        ))}
      </div>
      <audio ref={audioRef} src={tracks[current].url} onEnded={next}/>
    </div>
  );
}
render(<MusicPlayer/>);
